const StoryTitleWithCounts = ({ restaurantId, className }: { restaurantId?: string; className?: string }) => {
  const { t } = useTranslation();
  const { counts } = useStoryReactions(restaurantId);
  return (
    <span className={`flex items-center gap-2 ${className || ''}`}>
      <span className="text-xl">🏛️</span>
      {t("buildingStory.title", "Story")}
      {(counts.likes > 0 || counts.dislikes > 0) && (
        <span className="flex items-center gap-1.5 text-xs opacity-80">
          {counts.likes > 0 && <span className="flex items-center gap-0.5"><ThumbsUp className="w-3 h-3" />{counts.likes}</span>}
          {counts.dislikes > 0 && <span className="flex items-center gap-0.5"><ThumbsDown className="w-3 h-3" />{counts.dislikes}</span>}
        </span>
      )}
    </span>
  );
};

const StoryDialogContent = ({ restaurant }: { restaurant: any }) => {
  const { i18n, t } = useTranslation();
  const { user } = useAuth();
  const { buildingNarrative, iChingFull } = getBuildingStoryParts({
    photo_story_zh: restaurant?.photo_story_zh,
    photo_story_en: restaurant?.photo_story_en,
    photo_story_pt: restaurant?.photo_story_pt,
    address: restaurant?.address,
  }, i18n.language);
  // Auto-translate narrative to UI language
  const { translatedNarrative, isAutoTranslating } = useAutoTranslateNarrative(buildingNarrative || null, i18n.language);
  const { counts, userReaction, toggleReaction } = useStoryReactions(restaurant?.id);
  const [showComments, setShowComments] = useState(false);
  const { data: storyComments } = useComments(restaurant?.id || "", "story", { enabled: !!restaurant?.id });
  const commentsCount = storyComments?.reduce((acc: number, c: any) => acc + 1 + (c.replies?.length || 0), 0) || 0;

  const handleShare = async () => {
    try {
      if (navigator.share) {
        await navigator.share({ title: restaurant?.name || t("buildingStory.title", "Story"), url: window.location.href });
      } else {
        await navigator.clipboard.writeText(window.location.href);
        toast.success(t("common.linkCopied", "链接已复制"));
      }
    } catch { /* cancelled */ }
  };
  
  return (
    <div className="px-6 py-5 space-y-4">
      {buildingNarrative && (
        <>
          {isAutoTranslating && !translatedNarrative && (
            <div className="flex items-center gap-2 mb-3 text-sm text-muted-foreground">
              <Loader2 className="h-4 w-4 animate-spin" />
              <span>{t("translate.translating", "翻译中...")}</span>
            </div>
          )}
          <p className="whitespace-pre-line text-sm leading-[1.8] text-foreground/90">
            {translatedNarrative || buildingNarrative}
          </p>
        </>
      )}
      {iChingFull && (
        <div className="border-l-2 border-primary/30 pl-4 py-2 bg-secondary/50 rounded-r-md mt-4">
          <IChingSection text={iChingFull} />
        </div>
      )}
      {/* Like / Dislike / Share */}
      <div className="flex items-center justify-center gap-4 pt-2 border-t border-border/50">
        <button
          onClick={() => toggleReaction.mutate({ type: "like" })}
          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
            userReaction === "like" ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
          }`}
        >
          <ThumbsUp className={`w-4 h-4 ${userReaction === "like" ? "fill-primary" : ""}`} />
          {counts.likes > 0 && <span>{counts.likes}</span>}
        </button>
        <button
          onClick={() => toggleReaction.mutate({ type: "dislike" })}
          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
            userReaction === "dislike" ? "bg-destructive/15 text-destructive" : "text-muted-foreground hover:text-destructive hover:bg-destructive/10"
          }`}
        >
          <ThumbsDown className={`w-4 h-4 ${userReaction === "dislike" ? "fill-destructive" : ""}`} />
          {counts.dislikes > 0 && <span>{counts.dislikes}</span>}
        </button>
        <button
          onClick={handleShare}
          className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 active:scale-95"
        >
          <Share2 className="w-4 h-4" />
        </button>
        <button
          onClick={() => setShowComments(!showComments)}
          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
            showComments ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
          }`}
        >
          <MessageSquare className="w-4 h-4" />
          {commentsCount > 0 && <span>{commentsCount}</span>}
        </button>
      </div>
      {/* Story Comments */}
      {showComments && restaurant?.id && (
        <div className="mt-4 pt-4 border-t border-border/50">
          <RestaurantComments targetId={restaurant.id} targetType="story" />
        </div>
      )}
    </div>
  );
};

const RestaurantTags = ({
  restaurant,
  language
}: {
  restaurant: any;
  language: string;
}) => {
  const [visibleCount, setVisibleCount] = useState(999);
  const containerRef = useRef<HTMLDivElement>(null);
  const typeTags = restaurant.type.map((type: string, idx: number) => ({
    key: `type-${idx}`,
    label: getTypeDisplayLabel(type, language),
    variant: "secondary" as const,
    color: undefined
  }));
  const allTags = typeTags;
  useEffect(() => {
    const checkOverflow = () => {
      if (!containerRef.current) return;
      const container = containerRef.current;
      const badges = Array.from(container.querySelectorAll('.tag-badge')) as HTMLElement[];
      if (badges.length === 0) {
        setTimeout(checkOverflow, 50);
        return;
      }
      
      const firstBadgeTop = badges[0]?.offsetTop;
      let lastVisibleIndex = badges.length;

      // Find where tags overflow to second line
      for (let i = 0; i < badges.length; i++) {
        if (badges[i].offsetTop > firstBadgeTop) {
          lastVisibleIndex = i;
          break;
        }
      }

      // If all tags fit, no need for "..." button
      if (lastVisibleIndex === badges.length) {
        setVisibleCount(badges.length);
        return;
      }

      // Calculate available width and check if we need to reduce for "..." button
      const containerWidth = container.offsetWidth;
      const moreButtonWidth = 40; // Approximate width for "..." button
      
      // Calculate total width of visible tags
      let totalWidth = 0;
      let adjustedIndex = lastVisibleIndex;
      
      for (let i = 0; i < lastVisibleIndex; i++) {
        totalWidth += badges[i].offsetWidth + 8; // 8px gap
      }
      
      // If visible tags + button would overflow, reduce by 1
      if (totalWidth + moreButtonWidth > containerWidth) {
        adjustedIndex = Math.max(1, lastVisibleIndex - 1);
      }
      
      setVisibleCount(adjustedIndex);
    };
    setVisibleCount(999);
    const timer = setTimeout(checkOverflow, 100);
    window.addEventListener('resize', checkOverflow);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', checkOverflow);
    };
  }, [allTags.length, restaurant.id]);
  const visibleTags = allTags.slice(0, visibleCount);
  const hiddenTags = allTags.slice(visibleCount);
  const hasMore = hiddenTags.length > 0;
  return <div className="flex items-center gap-2 -mt-1">
      <div ref={containerRef} className="flex gap-2 flex-wrap flex-1">
        {visibleTags.map(tag => <Badge key={tag.key} variant={tag.variant} className="text-xs whitespace-nowrap tag-badge" style={tag.color ? {
        backgroundColor: tag.color,
        color: 'white'
      } : undefined}>
            {tag.label}
          </Badge>)}
      </div>
      {hasMore && <Popover>
          <PopoverTrigger asChild>
            <Button variant="ghost" size="sm" className="h-6 px-2 text-muted-foreground hover:text-foreground flex-shrink-0">
              <MoreHorizontal className="h-4 w-4" />
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto max-w-80">
            <div className="flex flex-wrap gap-2">
              {hiddenTags.map(tag => <Badge key={tag.key} variant={tag.variant} className="text-xs" style={tag.color ? {
            backgroundColor: tag.color,
            color: 'white'
          } : undefined}>
                  {tag.label}
                </Badge>)}
            </div>
          </PopoverContent>
        </Popover>}
    </div>;
};
const Restaurants = () => {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const {
    t,
    i18n
  } = useTranslation();
  const {
    toast
  } = useToast();
  const {
    localizeRestaurant
  } = useLocalizedContent();
  const isMobile = useIsMobile();
  const { requireLogin } = useLoginRequired();
  const { country: detectedCountry } = useUserCountry();
  const [searchQuery, setSearchQuery] = useState(() => {
    const saved = sessionStorage.getItem('restaurants-filter-search');
    if (saved && sessionStorage.getItem('restaurants-nav-from-detail')) return saved;
    return "";
  });
  const [translations, setTranslations] = useState<Record<string, string> | null>(null);
  const [activityTranslations, setActivityTranslations] = useState<Record<string, string>>({});
  const [templateFilter, setTemplateFilter] = useState<"all" | "default" | "ghost">(() => {
    const saved = sessionStorage.getItem('restaurants-filter-template');
    if (saved && sessionStorage.getItem('restaurants-nav-from-detail')) return saved as "all" | "default" | "ghost";
    return "all";
  });
  const [selectedTypes, setSelectedTypes] = useState<string[]>(() => {
    const saved = sessionStorage.getItem('restaurants-filter-types');
    if (saved && sessionStorage.getItem('restaurants-nav-from-detail')) {
      try { return JSON.parse(saved); } catch { return []; }
    }
    return [];
  });
  const [selectedCountry, setSelectedCountry] = useState<string | null>(() => {
    const saved = sessionStorage.getItem('restaurants-filter-country');
    if (saved && sessionStorage.getItem('restaurants-nav-from-detail')) return saved;
    return null;
  });
  const [selectedCity, setSelectedCity] = useState<string | null>(() => {
    const saved = sessionStorage.getItem('restaurants-filter-city');
    if (saved && sessionStorage.getItem('restaurants-nav-from-detail')) return saved;
    return null;
  });
  const [countrySearch, setCountrySearch] = useState("");
  const [citySearch, setCitySearch] = useState("");
  const [verifiedFilter, setVerifiedFilter] = useState<"all" | "verified" | "unverified">(() => {
    const saved = sessionStorage.getItem('restaurants-filter-verified');
    if (saved && sessionStorage.getItem('restaurants-nav-from-detail')) return saved as "all" | "verified" | "unverified";
    return "all";
  });
  const [selectedActivity, setSelectedActivity] = useState<string | null>(null);
  const [activityRestaurantIds, setActivityRestaurantIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<"list" | "map">("list");
  const [listColumns, setListColumns] = useState<1 | 2>(() => {
    const saved = localStorage.getItem('restaurant-list-columns');
    return (saved === '1' ? 1 : 2) as 1 | 2;
  });
  const [radiusFilter, setRadiusFilter] = useState<number | null>(null);
  const [userLocation, setUserLocation] = useState<{
    lat: number;
    lng: number;
  } | null>(() => {
    const saved = localStorage.getItem('restaurant-user-location');
    if (saved) {
      try { return JSON.parse(saved); } catch { return null; }
    }
    return null;
  });
  const [sortByDistance, setSortByDistance] = useState(() => {
    return localStorage.getItem('restaurant-sort-by-distance') === 'true';
  });
  const [showAllTypes, setShowAllTypes] = useState(false);
  const [filterOpen, setFilterOpen] = useState(false);
  const [showAllActivities, setShowAllActivities] = useState(false);
  const [showNavigationDialog, setShowNavigationDialog] = useState(false);
  const [showLocationDialog, setShowLocationDialog] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [navigationTarget, setNavigationTarget] = useState<{ lat: number; lng: number; name: string } | null>(null);
  const [storyDialog, setStoryDialog] = useState<{ id?: string; name: string; story: string; address?: string; image_url?: string | null; photo_story_zh?: string | null; photo_story_en?: string | null; photo_story_pt?: string | null } | null>(null);
  const [verifiedDialog, setVerifiedDialog] = useState(false);
  const [claimDialog, setClaimDialog] = useState<{ id: string; name: string; address?: string } | null>(null);
  const {
    user
  } = useAuth();
  const {
    data: restaurants,
    isLoading
  } = useRestaurants(searchQuery, selectedTypes.length > 0 ? selectedTypes.join(',') : undefined);
  const {
    data: favoriteIds = []
  } = useFavorites();
  const {
    data: restaurantTypes = []
  } = useRestaurantTypes();
  const { data: countries = [] } = useRestaurantCountries();
  const { data: cities = [] } = useRestaurantCities(selectedCountry);
  const {
    data: activities = []
  } = useActivities();
  const { data: activityRestaurantCounts = {} } = useActivityRestaurantCounts();

  // Save scroll position and displayed count when leaving, restore when returning from detail
  const [savedDisplayedCount] = useState<number | null>(() => {
    const shouldRestoreFromDetail = sessionStorage.getItem('restaurants-nav-from-detail') === '1';
    if (!shouldRestoreFromDetail) {
      sessionStorage.removeItem('restaurants-displayed-count');
      return null;
    }

    const saved = sessionStorage.getItem('restaurants-displayed-count');
    if (saved) {
      sessionStorage.removeItem('restaurants-displayed-count');
      return parseInt(saved, 10);
    }
    return null;
  });

  // Scroll position restoration for back navigation
  const isRestoringScroll = useRef(false);
  const savedScrollTarget = useRef<number | null>(null);

  // On mount: read saved scroll position (only if returning from detail)
  useEffect(() => {
    const fromDetail = sessionStorage.getItem('restaurants-nav-from-detail');
    if (fromDetail) {
      sessionStorage.removeItem('restaurants-nav-from-detail');
      const saved = sessionStorage.getItem('restaurants-scroll-pos');
      if (saved) {
        savedScrollTarget.current = parseInt(saved, 10);
        isRestoringScroll.current = true;
      }
    } else {
      // Fresh navigation - clear any stale saved state
      sessionStorage.removeItem('restaurants-scroll-pos');
      sessionStorage.removeItem('restaurants-filter-search');
      sessionStorage.removeItem('restaurants-filter-template');
      sessionStorage.removeItem('restaurants-filter-types');
      sessionStorage.removeItem('restaurants-filter-country');
      sessionStorage.removeItem('restaurants-filter-city');
      sessionStorage.removeItem('restaurants-filter-verified');
    }
  }, []);

  // Continuously save scroll position (skip during restoration)
  useEffect(() => {
    const handleScroll = () => {
      if (isRestoringScroll.current) return;
      sessionStorage.setItem('restaurants-scroll-pos', String(window.scrollY));
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  // Restore scroll after data loads
  useEffect(() => {
    if (savedScrollTarget.current != null && !isLoading) {
      const target = savedScrollTarget.current;
      savedScrollTarget.current = null;
      const timer = setTimeout(() => {
        window.scrollTo(0, target);
        setTimeout(() => { isRestoringScroll.current = false; }, 100);
      }, 150);
      return () => clearTimeout(timer);
    }
  }, [isLoading]);


  const handleRefresh = useCallback(async () => {
    // Clear caches to force fresh fetch
    queryClient.removeQueries({ queryKey: ['restaurants'] });
    queryClient.removeQueries({ queryKey: ['activities'] });
    queryClient.removeQueries({ queryKey: ['restaurantTypes'] });
    queryClient.removeQueries({ queryKey: ['favorites'] });
    queryClient.removeQueries({ queryKey: ['favorite-ids'] });
    
    // Refetch with fresh data
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ['restaurants'] }),
      queryClient.invalidateQueries({ queryKey: ['activities'] }),
      queryClient.invalidateQueries({ queryKey: ['restaurantTypes'] }),
      queryClient.invalidateQueries({ queryKey: ['favorites'] }),
      queryClient.invalidateQueries({ queryKey: ['favorite-ids'] }),
    ]);
  }, [queryClient]);

  // Filter activities to only show those with at least 1 restaurant
  const activitiesWithRestaurants = activities.filter(activity => (activityRestaurantCounts[activity.id] || 0) > 0);

  // Auto-translate activity badge texts for non-zh/en/pt languages
  const activityTranslationLangRef = useRef('');
  useEffect(() => {
    const lang = i18n.language;
    if (['zh', 'en', 'pt'].includes(lang) || activitiesWithRestaurants.length === 0) {
      if (['zh', 'en', 'pt'].includes(lang)) setActivityTranslations({});
      return;
    }

    // Skip if already translated for this language
    if (activityTranslationLangRef.current === lang && Object.keys(activityTranslations).length > 0) return;
    activityTranslationLangRef.current = lang;

    const textsToTranslate = activitiesWithRestaurants.map(a => 
      a.badge_text_en || a.title_en
    );

    const separator = "\n---ITEM_SEPARATOR---\n";
    const combinedText = textsToTranslate.join(separator);

    supabase.functions.invoke('translate-content', {
      body: { text: combinedText, targetLang: lang }
    }).then(({ data, error }) => {
      if (error || !data?.translatedText) return;
      const parts = data.translatedText.split(/---ITEM_SEPARATOR---/);
      const map: Record<string, string> = {};
      activitiesWithRestaurants.forEach((a, i) => {
        map[a.id] = (parts[i] || textsToTranslate[i]).trim();
      });
      setActivityTranslations(map);
    });
  }, [activitiesWithRestaurants.length, i18n.language]);

  const toggleFavorite = useToggleFavorite();
  const handleToggleFavorite = (restaurantId: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!user) {
      return;
    }
    toggleFavorite.mutate(restaurantId);
  };
  const handleTypeFilter = (type: string) => {
    setSelectedTypes(prev => {
      if (prev.includes(type)) {
        // Remove type if already selected
        return prev.filter(t => t !== type);
      } else {
        // Add type to selection
        return [...prev, type];
      }
    });
  };
  const handleRequestLocation = () => {
    if (sortByDistance) {
      // Already sorting by distance — toggle it off
      setSortByDistance(false);
      setUserLocation(null);
      localStorage.removeItem('restaurant-user-location');
      localStorage.removeItem('restaurant-sort-by-distance');
      return;
    }
    setShowLocationDialog(true);
  };
  
  // Persist location sorting preference
  useEffect(() => {
    if (userLocation) {
      localStorage.setItem('restaurant-user-location', JSON.stringify(userLocation));
    }
  }, [userLocation]);

  useEffect(() => {
    localStorage.setItem('restaurant-sort-by-distance', String(sortByDistance));
  }, [sortByDistance]);

  // Auto-locate on page mount
  useEffect(() => {
    // Always try to get location when entering the page
    setIsLocating(true);
    getUserLocation().then(position => {
      setUserLocation({
        lat: position.coords.latitude,
        lng: position.coords.longitude
      });
      setSortByDistance(true);
    }).catch(() => {
      // Silently handle — keep any cached location
    }).finally(() => {
      setIsLocating(false);
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Auto-fill country filter from detected user country (only on fresh navigation)
  const hasAutoFilledCountry = useRef(false);
  useEffect(() => {
    if (hasAutoFilledCountry.current) return;
    if (!detectedCountry) return;
    // Don't override if user already selected a country (e.g. restored from session)
    if (selectedCountry) { hasAutoFilledCountry.current = true; return; }
    setSelectedCountry(detectedCountry);
    hasAutoFilledCountry.current = true;
  }, [detectedCountry, selectedCountry]);

  const requestLocation = async () => {
    setShowLocationDialog(false);
    setIsLocating(true);
    try {
      const position = await getUserLocation();
      setUserLocation({
        lat: position.coords.latitude,
        lng: position.coords.longitude
      });
      setSortByDistance(true);
      toast({
        title: t("restaurants.locationEnabled"),
        description: t("restaurants.sortByDistance")
      });
    } catch (error: any) {
      console.error("Location error:", error);
      // Silently handle location errors - no toast notification
    } finally {
      setIsLocating(false);
    }
  };
  const handleRadiusChange = (radius: number | null) => {
    setRadiusFilter(radius);
    if (radius && !userLocation) {
      requestLocation();
    }
  };
  const handleActivityFilter = async (activityId: string) => {
    if (selectedActivity === activityId) {
      setSelectedActivity(null);
      setActivityRestaurantIds([]);
    } else {
      setSelectedActivity(activityId);
      // Fetch restaurants for this activity
      const {
        data,
        error
      } = await supabase.from("activity_restaurants").select("restaurant_id").eq("activity_id", activityId);
      if (error) {
        console.error("Error fetching activity restaurants:", error);
        setActivityRestaurantIds([]);
      } else {
        setActivityRestaurantIds(data.map(ar => ar.restaurant_id));
      }
    }
  };

  // Removed automatic location request - now manual only

  // Localize and process restaurants
  const processedRestaurants = restaurants?.map(restaurant => {
    const localized = localizeRestaurant(restaurant);
    if (userLocation) {
      const distance = calculateDistance(userLocation.lat, userLocation.lng, restaurant.lat, restaurant.lng);
      return {
        ...localized,
        distance
      };
    }
    return localized;
  }) || [];

   // Filter by template (physical vs ghost)
  const templateFilteredRestaurants = templateFilter === "all" 
    ? processedRestaurants 
    : processedRestaurants.filter(r => (r.template || "default") === templateFilter);

  // Filter by country/city
  const locationFilteredRestaurants = templateFilteredRestaurants.filter(r => {
    if (selectedCountry && (r as any).country !== selectedCountry) return false;
    if (selectedCity && (r as any).city !== selectedCity) return false;
    return true;
  });

  // Filter by verified status
  const verifiedFilteredRestaurants = verifiedFilter === "all"
    ? locationFilteredRestaurants
    : verifiedFilter === "verified"
    ? locationFilteredRestaurants.filter(r => (r as any).store_level === 'complete')
    : locationFilteredRestaurants.filter(r => (r as any).store_level !== 'complete');

  // Filter by activity - when activity is selected but has no restaurants, show empty list
  const activityFilteredRestaurants = selectedActivity 
    ? verifiedFilteredRestaurants.filter(r => activityRestaurantIds.includes(r.id)) 
    : verifiedFilteredRestaurants;

  // Filter by radius
  const filteredRestaurants = radiusFilter && userLocation ? activityFilteredRestaurants.filter(r => r.distance && r.distance <= radiusFilter) : activityFilteredRestaurants;
  // Sort: by distance if location available, otherwise by rating
  const sortedRestaurants = userLocation 
    ? [...filteredRestaurants].sort((a, b) => (a.distance || 0) - (b.distance || 0))
    : [...filteredRestaurants].sort((a, b) => (b.rating || 0) - (a.rating || 0));

  // Infinite scroll for list view
  const { displayedData: displayedRestaurants, hasMore, loadMore, reset, displayedCount } = useInfiniteScroll({
    data: sortedRestaurants,
    initialItemsPerPage: 12,
    incrementPerPage: 12,
    savedDisplayedCount,
  });

  // Save displayed count on unmount for scroll restoration
  useEffect(() => {
    return () => {
      sessionStorage.setItem('restaurants-displayed-count', String(displayedCount));
    };
  }, [displayedCount]);

  // Reset infinite scroll when filters change (skip initial mount to preserve restored count)
  const hasMountedRef = useRef(false);
  useEffect(() => {
    if (!hasMountedRef.current) {
      hasMountedRef.current = true;
      return;
    }
    reset();
  }, [searchQuery, selectedTypes, selectedActivity, radiusFilter, sortByDistance, templateFilter, selectedCountry, selectedCity, verifiedFilter, reset]);

  const handleRestaurantClick = (restaurant: any) => {
    sessionStorage.setItem('restaurants-nav-from-detail', '1');
    // Save current filters for restoration on back navigation
    sessionStorage.setItem('restaurants-filter-search', searchQuery);
    sessionStorage.setItem('restaurants-filter-template', templateFilter);
    sessionStorage.setItem('restaurants-filter-types', JSON.stringify(selectedTypes));
    sessionStorage.setItem('restaurants-filter-country', selectedCountry || '');
    sessionStorage.setItem('restaurants-filter-city', selectedCity || '');
    sessionStorage.setItem('restaurants-filter-verified', verifiedFilter);
    navigate(`/restaurant/${restaurant.id}`);
  };
  const pageContent = (
    <div className={`bg-secondary/20 animate-fade-in ${viewMode === "map" ? "h-screen flex flex-col overflow-hidden" : "min-h-screen py-8 px-4"}`}>
      <div className={`${viewMode === "map" ? "flex flex-col h-full" : "container mx-auto max-w-7xl"}`}>
        {/* Header */}
        <div className={`${viewMode === "map" ? "px-4 pt-4 pb-2 flex-shrink-0" : "mb-8"}`}>
          <div className="flex items-center justify-between mb-4">
            <h1 className={`text-3xl sm:text-4xl font-medium text-primary ${viewMode === "map" ? "hidden md:block" : ""}`}>{t("restaurants.title")}</h1>
            <TranslateAllButton
              items={displayedRestaurants.map(r => ({ id: r.id, text: `${r.name}\n${r.address || ''}` }))}
              onTranslations={setTranslations}
            />
          </div>
          
          {/* Template Tabs */}
          <Tabs value={templateFilter} onValueChange={(v) => setTemplateFilter(v as "all" | "default" | "ghost")} className="mb-4">
            <TabsList className="w-full sm:w-auto">
              <TabsTrigger value="all" className="flex-1 sm:flex-auto">{t("restaurants.tabAll")}</TabsTrigger>
              <TabsTrigger value="default" className="flex-1 sm:flex-auto">{t("restaurants.tabPhysical")}</TabsTrigger>
              <TabsTrigger value="ghost" className="flex-1 sm:flex-auto">{t("restaurants.tabGhost")}</TabsTrigger>
            </TabsList>
          </Tabs>
          <div className="flex flex-col gap-3">
            {/* Row 1: Search + Action Buttons */}
            <div className="flex gap-2 items-center">
              <Input 
                placeholder={t("restaurants.search")} 
                value={searchQuery} 
                onChange={e => setSearchQuery(e.target.value)} 
                className="flex-1 md:max-w-md" 
              />
              
              {/* Location Button */}
              <Button 
                variant={userLocation ? "default" : "outline"} 
                size="icon" 
                onClick={handleRequestLocation}
                disabled={isLocating}
                className="h-10 w-10 flex-shrink-0"
                title={isLocating ? t("restaurants.locating", "定位中...") : t("restaurants.getLocation")}
              >
                {isLocating ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Navigation className="h-4 w-4" />
                )}
              </Button>
              
              {/* View Toggle Group */}
              <div className="inline-flex h-10 items-center justify-center rounded-md bg-muted p-1 text-muted-foreground flex-shrink-0">
                <button 
                  onClick={() => {
                    if (viewMode === "list") {
                      if (isMobile) {
                        const newColumns = listColumns === 2 ? 1 : 2;
                        setListColumns(newColumns);
                        localStorage.setItem('restaurant-list-columns', String(newColumns));
                      }
                    } else {
                      setViewMode("list");
                    }
                  }} 
                  className={`inline-flex items-center justify-center rounded-sm px-2.5 py-1.5 transition-all ${
                    viewMode === "list" ? 'bg-background text-foreground shadow-sm' : ''
                  }`}
                >
                  {viewMode === "list" && isMobile && listColumns === 1 ? (
                    <LayoutGrid className="h-4 w-4" />
                  ) : (
                    <List className="h-4 w-4" />
                  )}
                </button>
                <button 
                  onClick={() => setViewMode("map")} 
                  className={`inline-flex items-center justify-center rounded-sm px-2.5 py-1.5 transition-all ${
                    viewMode === "map" ? 'bg-background text-foreground shadow-sm' : ''
                  }`}
                >
                  <Map className="h-4 w-4" />
                </button>
              </div>

              {/* Filter Sheet Trigger */}
              <Sheet open={filterOpen} onOpenChange={setFilterOpen}>
                <SheetTrigger asChild>
                  <Button 
                    variant="outline" 
                    size="icon" 
                    className="h-10 w-10 flex-shrink-0 relative"
                  >
                    <Filter className="h-4 w-4" />
                    {(selectedActivity || radiusFilter || selectedCountry || selectedCity || verifiedFilter !== "all" || selectedTypes.length > 0) && (
                      <span className="absolute -top-1 -right-1 h-4 w-4 rounded-full bg-primary text-primary-foreground text-[10px] flex items-center justify-center font-medium">
                        {(selectedActivity ? 1 : 0) + (radiusFilter ? 1 : 0) + (selectedCountry ? 1 : 0) + (selectedCity ? 1 : 0) + (verifiedFilter !== "all" ? 1 : 0) + (selectedTypes.length > 0 ? 1 : 0)}
                      </span>
                    )}
                  </Button>
                </SheetTrigger>
                <SheetContent side={isMobile ? "bottom" : "right"} className={`${isMobile ? 'h-[85vh] rounded-t-2xl' : 'w-[400px]'} p-0 flex flex-col`}>
                  {/* Sheet Header */}
                  <div className="flex items-center justify-between px-5 py-4 border-b border-border/50">
                    <SheetTitle className="text-lg font-semibold">{t("restaurants.filter")}</SheetTitle>
                    {(selectedActivity || radiusFilter || selectedCountry || selectedCity || verifiedFilter !== "all" || selectedTypes.length > 0) && (
                      <Button
                        variant="ghost"
                        size="sm"
                        className="h-8 px-3 text-xs text-destructive hover:text-destructive hover:bg-destructive/10 rounded-full"
                        onClick={() => {
                          setSelectedTypes([]);
                          setSelectedActivity(null);
                          setActivityRestaurantIds([]);
                          setRadiusFilter(null);
                          setSelectedCountry(null);
                          setSelectedCity(null);
                          setVerifiedFilter("all");
                        }}
                      >
                        <X className="w-3.5 h-3.5 mr-1" />
                        {t("common.actions.clearFilter")}
                      </Button>
                    )}
                  </div>

                  {/* Sheet Body - Scrollable */}
                  <div className="flex-1 overflow-y-auto px-5 py-4 space-y-6">
                    
                    {/* Restaurant Type Filter */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-semibold text-foreground">{t("restaurants.storeTypes", "商店类型")}</span>
                        {selectedTypes.length > 0 && (
                          <Button
                            variant="ghost"
                            size="sm"
                            className="h-7 px-2 text-xs text-destructive hover:text-destructive hover:bg-destructive/10 rounded-full"
                            onClick={() => setSelectedTypes([])}
                          >
                            <X className="w-3 h-3 mr-1" />
                            {t("common.actions.clear")}
                          </Button>
                        )}
                      </div>
                      <div className="flex gap-2 flex-wrap">
                        {restaurantTypes.map((type) => (
                          <button
                            key={type}
                            onClick={() => handleTypeFilter(type)}
                            className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                              selectedTypes.includes(type)
                                ? 'bg-primary text-primary-foreground border-primary shadow-sm'
                                : 'bg-background text-foreground border-border/60 hover:border-primary/40 hover:bg-muted/50'
                            }`}
                          >
                            {getTypeDisplayLabel(type, i18n.language)}
                          </button>
                        ))}
                      </div>
                    </div>

                    <Separator />

                    {/* Verified Filter */}
                    <div className="space-y-3">
                      <div className="flex items-center gap-2">
                        <ShieldCheck className="w-4 h-4 text-muted-foreground" />
                        <span className="text-sm font-semibold text-foreground">{t("restaurants.verificationStatus", "认证状态")}</span>
                      </div>
                      <div className="grid grid-cols-3 gap-2">
                        {([
                          { value: "all" as const, label: t("restaurants.allStores", "全部"), icon: null as React.ReactNode },
                          { value: "verified" as const, label: t("restaurants.verifiedOnly", "已认证"), icon: <BadgeCheck className="w-4 h-4" /> as React.ReactNode },
                          { value: "unverified" as const, label: t("restaurants.unverifiedOnly", "未认证"), icon: <HandMetal className="w-4 h-4" /> as React.ReactNode },
                        ]).map((option) => (
                          <button
                            key={option.value}
                            onClick={() => setVerifiedFilter(option.value)}
                            className={`flex flex-col items-center gap-1.5 p-3 rounded-xl border-2 transition-all duration-200 ${
                              verifiedFilter === option.value
                                ? 'border-primary bg-primary/5 text-primary shadow-sm'
                                : 'border-border/50 bg-background text-muted-foreground hover:border-primary/30 hover:bg-muted/50'
                            }`}
                          >
                            {option.icon && <span>{option.icon}</span>}
                            <span className="text-xs font-medium">{option.label}</span>
                          </button>
                        ))}
                      </div>
                    </div>

                    <Separator />

                    {/* Activity Filter */}
                    {activitiesWithRestaurants.length > 0 && (
                      <>
                        <div className="space-y-3">
                          <div className="flex items-center justify-between">
                            <span className="text-sm font-semibold text-foreground">{t("nav.activities")}</span>
                            <div className="flex items-center gap-2">
                              {selectedActivity && (
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  className="h-7 px-2 text-xs text-destructive hover:text-destructive hover:bg-destructive/10 rounded-full"
                                  onClick={() => {
                                    setSelectedActivity(null);
                                    setActivityRestaurantIds([]);
                                  }}
                                >
                                  <X className="w-3 h-3 mr-1" />
                                  {t("common.actions.clear")}
                                </Button>
                              )}
                              {activitiesWithRestaurants.length > 6 && (
                                <Button
                                  variant="link"
                                  size="sm"
                                  className="h-auto p-0 text-xs text-primary hover:text-primary/80"
                                  onClick={() => setShowAllActivities(!showAllActivities)}
                                >
                                  {showAllActivities ? t("common.showLess") : t("common.showMore")}
                                </Button>
                              )}
                            </div>
                          </div>
                          <div className="flex gap-2 flex-wrap">
                            {(showAllActivities ? activitiesWithRestaurants : activitiesWithRestaurants.slice(0, 6)).map((activity) => {
                              const lang = i18n.language;
                              const badgeText = activityTranslations[activity.id] 
                                || (lang === 'zh' 
                                  ? (activity.badge_text_zh || activity.title_zh)
                                  : lang === 'pt' 
                                  ? (activity.badge_text_pt || activity.title_pt)
                                  : (activity.badge_text_en || activity.title_en));
                              return (
                                <button
                                  key={activity.id}
                                  onClick={() => handleActivityFilter(activity.id)}
                                  className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                                    selectedActivity === activity.id 
                                      ? 'bg-primary text-primary-foreground border-primary shadow-sm' 
                                      : 'bg-background text-foreground border-border/60 hover:border-primary/40 hover:bg-muted/50'
                                  }`}
                                >
                                  {badgeText}
                                </button>
                              );
                            })}
                          </div>
                        </div>
                        <Separator />
                      </>
                    )}
                  </div>

                  {/* Sheet Footer - Apply Button */}
                  <div className="px-5 py-4 border-t border-border/50 bg-background">
                    <Button className="w-full" onClick={() => setFilterOpen(false)}>
                      {t("common.actions.apply", "应用筛选")} ({sortedRestaurants.length} {t("restaurants.results", "结果")})
                    </Button>
                  </div>
                </SheetContent>
              </Sheet>
            </div>

            {/* Row 2: Location & Radius in one row */}
            <div className="flex items-center gap-2 overflow-x-auto pb-1 -mx-1 px-1 scrollbar-none">
              {/* Country dropdown */}
              {countries.length > 0 && (
                <Popover onOpenChange={(open) => { if (!open) setCountrySearch(""); }}>
                  <PopoverTrigger asChild>
                    <button className={`flex-shrink-0 flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                      selectedCountry 
                        ? 'bg-primary text-primary-foreground border-primary shadow-sm' 
                        : 'bg-background text-foreground border-border/60 hover:border-primary/40 hover:bg-muted/50'
                    }`}>
                      <Globe className="w-3 h-3" />
                      {selectedCountry || t("restaurants.allCountries", "全部国家")}
                      {selectedCountry && (
                        <X className="w-3 h-3 ml-0.5 opacity-70 hover:opacity-100" onClick={(e) => { e.stopPropagation(); setSelectedCountry(null); setSelectedCity(null); }} />
                      )}
                    </button>
                  </PopoverTrigger>
                  <PopoverContent className="w-52 p-2" align="start">
                    {countries.length > 5 && (
                      <div className="pb-2">
                        <Input
                          placeholder={t("common.search", "搜索") + "..."}
                          value={countrySearch}
                          onChange={(e) => setCountrySearch(e.target.value)}
                          className="h-8 text-sm"
                          autoFocus
                        />
                      </div>
                    )}
                    <div className="space-y-0.5 max-h-[280px] overflow-y-auto">
                      {!countrySearch && (
                        <button
                          onClick={() => { setSelectedCountry(null); setSelectedCity(null); }}
                          className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                            !selectedCountry ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-muted'
                          }`}
                        >
                          {t("restaurants.allCountries", "全部国家")}
                        </button>
                      )}
                      {countries
                        .filter(c => !countrySearch || c.toLowerCase().includes(countrySearch.toLowerCase()))
                        .map((country) => (
                        <button
                          key={country}
                          onClick={() => { setSelectedCountry(selectedCountry === country ? null : country); setSelectedCity(null); setCountrySearch(""); }}
                          className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                            selectedCountry === country ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-muted'
                          }`}
                        >
                          {country}
                        </button>
                      ))}
                      {countrySearch && countries.filter(c => c.toLowerCase().includes(countrySearch.toLowerCase())).length === 0 && (
                        <p className="px-3 py-2 text-sm text-muted-foreground">{t("common.noResults", "无结果")}</p>
                      )}
                    </div>
                  </PopoverContent>
                </Popover>
              )}

              {/* City dropdown - only when country selected */}
              {selectedCountry && cities.length > 0 && (
                <Popover onOpenChange={(open) => { if (!open) setCitySearch(""); }}>
                  <PopoverTrigger asChild>
                    <button className={`flex-shrink-0 flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border ${
                      selectedCity 
                        ? 'bg-primary/90 text-primary-foreground border-primary/90 shadow-sm' 
                        : 'bg-background text-foreground border-border/60 hover:border-primary/40 hover:bg-muted/50'
                    }`}>
                      <Building2 className="w-3 h-3" />
                      {selectedCity || t("restaurants.allCities", "全部城市")}
                      {selectedCity && (
                        <X className="w-3 h-3 ml-0.5 opacity-70 hover:opacity-100" onClick={(e) => { e.stopPropagation(); setSelectedCity(null); }} />
                      )}
                    </button>
                  </PopoverTrigger>
                  <PopoverContent className="w-52 p-2" align="start">
                    {cities.length > 5 && (
                      <div className="pb-2">
                        <Input
                          placeholder={t("common.search", "搜索") + "..."}
                          value={citySearch}
                          onChange={(e) => setCitySearch(e.target.value)}
                          className="h-8 text-sm"
                          autoFocus
                        />
                      </div>
                    )}
                    <div className="space-y-0.5 max-h-[280px] overflow-y-auto">
                      {!citySearch && (
                        <button
                          onClick={() => setSelectedCity(null)}
                          className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                            !selectedCity ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-muted'
                          }`}
                        >
                          {t("restaurants.allCities", "全部城市")}
                        </button>
                      )}
                      {cities
                        .filter(c => !citySearch || c.toLowerCase().includes(citySearch.toLowerCase()))
                        .map((city) => (
                        <button
                          key={city}
                          onClick={() => { setSelectedCity(selectedCity === city ? null : city); setCitySearch(""); }}
                          className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                            selectedCity === city ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-muted'
                          }`}
                        >
                          {city}
                        </button>
                      ))}
                      {citySearch && cities.filter(c => c.toLowerCase().includes(citySearch.toLowerCase())).length === 0 && (
                        <p className="px-3 py-2 text-sm text-muted-foreground">{t("common.noResults", "无结果")}</p>
                      )}
                    </div>
                  </PopoverContent>
                </Popover>
              )}

              {/* Separator */}
              {countries.length > 0 && <div className="w-px h-5 bg-border/60 flex-shrink-0" />}

              {/* Radius chips */}
              {[
                { value: null, label: t("restaurants.all", "全部") },
                { value: 5, label: "5km" },
                { value: 10, label: "10km" },
                { value: 20, label: "20km" },
                { value: 50, label: "50km" },
              ].map((option) => (
                <button
                  key={option.value ?? 'all'}
                  onClick={() => handleRadiusChange(option.value)}
                  className={`flex-shrink-0 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-200 border flex items-center gap-1 ${
                    radiusFilter === option.value
                      ? 'bg-primary text-primary-foreground border-primary shadow-sm'
                      : 'bg-background text-foreground border-border/60 hover:border-primary/40 hover:bg-muted/50'
                  }`}
                >
                  {option.value === null && <Navigation className="w-3 h-3" />}
                  {option.label}
                </button>
              ))}
            </div>

            {/* Row: Active filter tags summary */}
            {(selectedActivity || selectedCountry || selectedCity || verifiedFilter !== "all" || radiusFilter || selectedTypes.length > 0) && (
              <div className="flex items-center gap-2 flex-wrap">
                <span className="text-xs text-muted-foreground">{t("restaurants.activeFilters", "筛选中")}:</span>
                {selectedTypes.length > 0 && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {selectedTypes.map(t => getTypeDisplayLabel(t, i18n.language)).join(', ')}
                    <button onClick={() => setSelectedTypes([])} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
                {verifiedFilter !== "all" && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {verifiedFilter === "verified" ? t("restaurants.verifiedOnly", "已认证") : t("restaurants.unverifiedOnly", "未认证")}
                    <button onClick={() => setVerifiedFilter("all")} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
                {selectedCountry && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {selectedCountry}{selectedCity ? ` · ${selectedCity}` : ''}
                    <button onClick={() => { setSelectedCountry(null); setSelectedCity(null); }} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
                {selectedActivity && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {(() => {
                      const a = activitiesWithRestaurants.find(a => a.id === selectedActivity);
                      if (!a) return '';
                      const lang = i18n.language;
                      return activityTranslations[a.id] || (lang === 'zh' ? (a.badge_text_zh || a.title_zh) : lang === 'pt' ? (a.badge_text_pt || a.title_pt) : (a.badge_text_en || a.title_en));
                    })()}
                    <button onClick={() => { setSelectedActivity(null); setActivityRestaurantIds([]); }} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
                {radiusFilter && (
                  <Badge variant="secondary" className="text-xs gap-1 pr-1">
                    {radiusFilter} km
                    <button onClick={() => setRadiusFilter(null)} className="ml-0.5 hover:text-destructive"><X className="w-3 h-3" /></button>
                  </Badge>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Content Area */}
        {/* Loading State - Show skeleton immediately, don't wait for undefined */}
        {(isLoading || !restaurants) ? (
          viewMode === "map" ? (
            <MapViewSkeleton />
          ) : (
            <RestaurantListSkeleton count={6} />
          )
        ) : sortedRestaurants.length === 0 ? (
          /* Empty State */
          <div className={`text-center ${viewMode === "map" ? "flex-1 flex flex-col justify-center px-4" : "py-20"}`}>
            <p className="text-xl text-muted-foreground">{t("restaurants.noResults")}</p>
            <p className="text-muted-foreground mt-2">{t("restaurants.noResultsDesc")}</p>
          </div>
        ) : (
          /* Content */
          <>
            {/* Map View */}
            {viewMode === "map" && sortedRestaurants.length > 0 && (
              <div className="relative flex-1 min-h-[300px] sm:min-h-[400px] lg:mx-4 lg:mb-4 lg:rounded-lg overflow-hidden lg:shadow-lg">
                <RestaurantMap restaurants={sortedRestaurants} onRestaurantClick={handleRestaurantClick} userLocation={userLocation} radiusFilter={radiusFilter} showViewDetailsButton={true} />
                {/* Logo and text in bottom left corner of map */}
                <div className="absolute bottom-4 left-4 z-10 pointer-events-none flex items-center gap-2 bg-background/90 px-3 py-2 rounded-full shadow-lg">
                  <img 
                    src={logoIcon} 
                    alt="Xiaoxiong Market Logo" 
                    className="h-6 w-6 object-contain"
                  />
                  <span className="text-sm font-semibold text-foreground whitespace-nowrap">
                    {i18n.language === 'zh' ? '小熊市场' : 'Xiaoxiong Market'}
                  </span>
                </div>
              </div>
            )}

            {/* List View */}
            {viewMode === "list" && sortedRestaurants.length > 0 && (
              <>
                <div className={`grid gap-6 ${listColumns === 1 ? 'grid-cols-1' : 'grid-cols-2'} md:grid-cols-2 lg:grid-cols-3`}>
                  {displayedRestaurants.map(restaurant => {
                    // Compact mode: mobile + 2 columns
                    const isCompactMode = isMobile && listColumns === 2;
                    
                    return (
                      <Card key={restaurant.id} className={`overflow-hidden hover:shadow-large transition-shadow flex flex-col h-full ${isCompactMode ? 'gap-0' : ''}`}>
                        <div className={`relative overflow-hidden ${isCompactMode ? 'h-28' : 'h-48'}`}>
                          <img loading="lazy" src={restaurant.image_url || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=600&q=80"} alt={restaurant.name} className="w-full h-full object-cover transition-transform hover:scale-105" />
                          {user && (
                            <Button size="icon" variant="secondary" className={`absolute ${isCompactMode ? 'top-1.5 right-1.5 h-7 w-7' : 'top-3 right-3'}`} onClick={e => handleToggleFavorite(restaurant.id, e)}>
                              <Heart className={`${isCompactMode ? 'w-3.5 h-3.5' : 'w-5 h-5'} ${favoriteIds.includes(restaurant.id) ? "fill-destructive text-destructive" : ""}`} />
                            </Button>
                          )}
                          {(() => {
                            const hasStory = restaurant.photo_story_zh || restaurant.photo_story_en || restaurant.photo_story_pt;
                            if (!hasStory) return null;
                            return (
                              <button 
                                className={`absolute ${isCompactMode ? 'bottom-1.5 left-1.5' : 'bottom-3 left-3'} z-20 group flex items-center gap-2`}
                                onClick={e => {
                                  e.stopPropagation();
                                  e.preventDefault();
                                  const displayName = i18n.language === 'zh' ? restaurant.name : (i18n.language === 'pt' ? (restaurant.name_pt || restaurant.name_en || restaurant.name) : (restaurant.name_en || restaurant.name));
                                  setStoryDialog({ id: restaurant.id, name: displayName, story: hasStory, address: restaurant.address, image_url: restaurant.image_url, photo_story_zh: restaurant.photo_story_zh, photo_story_en: restaurant.photo_story_en, photo_story_pt: restaurant.photo_story_pt });
                                }}
                              >
                                <span className="relative flex h-3 w-3">
                                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-white/70 opacity-75" />
                                  <span className="relative inline-flex rounded-full h-3 w-3 bg-white shadow-lg" />
                                </span>
                                {!isCompactMode && (
                                  <span className="text-xs text-white/80 opacity-0 group-hover:opacity-100 transition-opacity duration-300 drop-shadow-md">
                                    {i18n.language === 'zh' ? '建筑故事' : i18n.language === 'pt' ? 'História' : 'Story'}
                                  </span>
                                )}
                              </button>
                            );
                          })()}
                          {(restaurant as any).store_level === 'complete' && (
                            <button
                              className={`absolute ${isCompactMode ? 'top-1.5 left-1.5' : 'top-3 left-3'} z-20 bg-primary/90 rounded-full ${isCompactMode ? 'p-1' : 'p-1.5'} shadow-md hover:bg-primary transition-colors`}
                              onClick={(e) => {
                                e.stopPropagation();
                                e.preventDefault();
                                setVerifiedDialog(true);
                              }}
                              title={t("restaurants.verifiedStore")}
                            >
                              <BadgeCheck className={`${isCompactMode ? 'w-3.5 h-3.5' : 'w-4 h-4'} text-primary-foreground`} />
                            </button>
                          )}
                          {(restaurant as any).store_level === 'shell' && (
                            <button
                              className={`absolute ${isCompactMode ? 'top-1.5 left-1.5' : 'top-3 left-3'} z-20 bg-primary/90 rounded-full ${isCompactMode ? 'px-1.5 py-0.5' : 'px-2.5 py-1'} shadow-md hover:bg-primary transition-colors flex items-center gap-1`}
                              onClick={(e) => {
                                e.stopPropagation();
                                e.preventDefault();
                                if (!requireLogin()) return;
                                setClaimDialog({
                                  id: restaurant.id,
                                  name: restaurant.name,
                                  address: restaurant.address,
                                });
                              }}
                              title={t("restaurants.unclaimedStore", "未认领")}
                            >
                              <HandMetal className={`${isCompactMode ? 'w-3 h-3' : 'w-3.5 h-3.5'} text-primary-foreground`} />
                              {!isCompactMode && (
                                <span className="text-xs font-medium text-primary-foreground">
                                  {t("restaurants.unclaimedStore", "未认领")}
                                </span>
                              )}
                            </button>
                          )}
                        </div>
                        
                        <CardHeader className={isCompactMode ? 'p-2 pb-1' : 'mb-px pb-[15px]'}>
                          <div className="flex items-start justify-between">
                            <div className={`flex flex-col ${isCompactMode ? 'gap-0.5' : 'gap-2'}`}>
                              <h3 className={`font-semibold text-card-foreground ${isCompactMode ? 'text-sm line-clamp-2' : 'text-xl'}`}>
                                {(() => {
                                  if (translations && translations[restaurant.id]) {
                                    const parts = translations[restaurant.id].split('\n');
                                    return formatTrademarkSymbols(parts[0] || restaurant.name);
                                  }
                                  return formatTrademarkSymbols(restaurant.name);
                                })()}
                              </h3>
                              {restaurant.distance !== undefined && (
                                <div className="flex items-center gap-1">
                                  <Navigation className={`text-primary ${isCompactMode ? 'w-3 h-3' : 'w-4 h-4'}`} />
                                  <span className={`font-semibold text-foreground ${isCompactMode ? 'text-xs' : 'text-sm'}`}>
                                    {restaurant.distance.toFixed(1)} km
                                  </span>
                                </div>
                              )}
                            </div>
                            <div className="flex items-center gap-0.5">
                              <Star className={`${isCompactMode ? 'w-3.5 h-3.5' : 'w-5 h-5'} ${restaurant.rating ? "fill-accent text-accent" : "text-muted-foreground"}`} />
                              {restaurant.rating ? (
                                <span className={`font-semibold text-card-foreground ${isCompactMode ? 'text-xs' : ''}`}>
                                  {restaurant.rating.toFixed(1)}
                                </span>
                              ) : !isCompactMode && (
                                <span className="text-xs text-muted-foreground text-center whitespace-nowrap">
                                  {t("restaurant.noRatingLine1")}<br />{t("restaurant.noRatingLine2")}
                                </span>
                              )}
                            </div>
                          </div>
                        </CardHeader>

                        <CardContent className={`flex-grow ${isCompactMode ? 'p-2 pt-0 space-y-1' : 'space-y-2'}`}>
                          {/* Type Tags */}
                          <div className={`flex items-center flex-wrap ${isCompactMode ? 'gap-1' : 'gap-2'}`}>
                            {isCompactMode ? (
                              // Compact: show only first 2 tags
                              restaurant.type.slice(0, 2).map((type: string, idx: number) => (
                                <Badge key={`type-${idx}`} variant="secondary" className="text-xs px-1.5 py-0.5">
                                  {getTypeDisplayLabel(type, i18n.language)}
                                </Badge>
                              ))
                            ) : (
                              <>
                                <RestaurantTags restaurant={restaurant} language={i18n.language} />
                                {(restaurant as any).template === 'ghost' && (
                                  <Badge variant="outline" className="text-xs">
                                    {t("restaurants.ghostKitchen")}
                                  </Badge>
                                )}
                              </>
                            )}
                          </div>
                          
                          {/* Address - hide in compact mode */}
                          {!isCompactMode && (
                            <div className="flex items-center gap-2 text-muted-foreground text-sm">
                              <MapPin className="w-4 h-4 flex-shrink-0" />
                              <span className="line-clamp-1">{
                                translations && translations[restaurant.id]
                                  ? (translations[restaurant.id].split('\n')[1] || restaurant.address)
                                  : restaurant.address
                              }</span>
                            </div>
                          )}
                          {/* Building Story Snippet - hide in compact mode */}
                          {!isCompactMode && (() => {
                            const snippet = getBuildingStorySnippet(restaurant);
                            if (!snippet) return null;
                            return (
                              <div 
                                className="flex items-start gap-2 text-xs text-muted-foreground bg-muted/40 rounded-md px-2.5 py-1.5 cursor-pointer hover:bg-muted/60 transition-colors"
                                onClick={(e) => {
                                  e.stopPropagation();
                                  e.preventDefault();
                                  const displayName = i18n.language === 'zh' ? restaurant.name : (i18n.language === 'pt' ? (restaurant.name_pt || restaurant.name_en || restaurant.name) : (restaurant.name_en || restaurant.name));
                                  setStoryDialog({ id: restaurant.id, name: displayName, story: snippet, address: restaurant.address, image_url: restaurant.image_url, photo_story_zh: restaurant.photo_story_zh, photo_story_en: restaurant.photo_story_en, photo_story_pt: restaurant.photo_story_pt });
                                }}
                              >
                                <Landmark className="w-3.5 h-3.5 text-primary flex-shrink-0 mt-0.5" />
                                <span className="line-clamp-2 italic leading-relaxed">{snippet}</span>
                              </div>
                            );
                          })()}
                          {/* Phone - hide in compact mode */}
                          {!isCompactMode && restaurant.phone && (
                            <div className="flex items-center gap-2 text-muted-foreground text-sm">
                              <Phone className="w-4 h-4 flex-shrink-0" />
                              <span>{restaurant.phone}</span>
                            </div>
                          )}
                          {/* Opening hours - hide in compact mode */}
                          {!isCompactMode && restaurant.opening_hours && (
                            <div className="flex items-center gap-2 text-muted-foreground text-sm">
                              <Clock className="w-4 h-4 flex-shrink-0" />
                              <span>{formatOpeningHours(restaurant.opening_hours)}</span>
                            </div>
                          )}
                        </CardContent>

                        <CardFooter className={`mt-auto ${isCompactMode ? 'p-2 pt-0' : 'gap-2'}`}>
                          <Button asChild className={`flex-1 ${isCompactMode ? 'h-7 text-xs' : ''}`} size={isCompactMode ? 'sm' : 'default'}>
                            <Link to={`/restaurant/${restaurant.id}`} onClick={() => sessionStorage.setItem('restaurants-nav-from-detail', '1')}>{t("restaurants.viewDetails")}</Link>
                          </Button>
                          {!isCompactMode && userLocation && (
                            <Button variant="outline" size="icon" onClick={() => {
                              setNavigationTarget({ lat: restaurant.lat, lng: restaurant.lng, name: restaurant.name });
                              setShowNavigationDialog(true);
                            }} title={t("restaurants.directions")}>
                              <Navigation className="w-4 h-4" />
                            </Button>
                          )}
                        </CardFooter>
                      </Card>
                    );
                  })}
                </div>
                
                {/* Load More Button */}
                {hasMore && (
                  <div className="flex justify-center mt-8">
                    <Button onClick={loadMore} size="lg" variant="outline">
                      {t("common.loadMore")} ({displayedRestaurants.length} / {sortedRestaurants.length})
                    </Button>
                  </div>
                )}
              </>
            )}
          </>
        )}

        <NavigationConfirmDialog
          open={showNavigationDialog}
          onOpenChange={setShowNavigationDialog}
          onConfirm={() => {
            if (navigationTarget) {
              openNavigation(navigationTarget.lat, navigationTarget.lng, navigationTarget.name);
            }
            setShowNavigationDialog(false);
          }}
          destinationName={navigationTarget?.name || ""}
        />

        <LocationPermissionDialog
          open={showLocationDialog}
          onOpenChange={setShowLocationDialog}
          onConfirm={requestLocation}
        />

        <Dialog open={!!storyDialog} onOpenChange={(open) => !open && setStoryDialog(null)}>
          <DialogContent className="max-w-md max-h-[80vh] overflow-y-auto p-0 gap-0 border-none">
            {/* Hero image */}
            {storyDialog?.image_url && (
              <div className="relative w-full h-48 overflow-hidden rounded-t-lg">
                <img 
                  src={storyDialog.image_url} 
                  alt={storyDialog?.name || ''} 
                  className="w-full h-full object-cover"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-transparent" />
                <div className="absolute bottom-0 left-0 right-0 px-5 pb-4">
                  <DialogHeader>
                    <DialogTitle className="text-lg text-white flex items-center gap-2 drop-shadow-lg">
                      <StoryTitleWithCounts restaurantId={storyDialog?.id} className="text-white" />
                    </DialogTitle>
                    <DialogDescription className="text-sm text-white/80 mt-0.5 drop-shadow">
                      {storyDialog?.name}
                    </DialogDescription>
                  </DialogHeader>
                </div>
              </div>
            )}
            {/* Fallback header when no image */}
            {!storyDialog?.image_url && (
              <div className="relative bg-gradient-to-br from-primary/90 via-primary-light/80 to-accent/85 px-6 pt-6 pb-5 rounded-t-lg">
                <div className="absolute inset-0 opacity-[0.06] rounded-t-lg" style={{ backgroundImage: 'url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.4\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")' }} />
                <DialogHeader className="relative z-10">
                  <DialogTitle className="text-lg text-primary-foreground flex items-center gap-2">
                    <StoryTitleWithCounts restaurantId={storyDialog?.id} />
                  </DialogTitle>
                  <DialogDescription className="text-sm text-primary-foreground/70 mt-1">
                    {storyDialog?.name}
                  </DialogDescription>
                </DialogHeader>
              </div>
            )}
            {/* Story content */}
            <StoryDialogContent restaurant={storyDialog} />
          </DialogContent>
        </Dialog>

        {/* Verified Store Dialog */}
        <Dialog open={verifiedDialog} onOpenChange={setVerifiedDialog}>
          <DialogContent className="max-w-sm">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2">
                <BadgeCheck className="w-5 h-5 text-primary fill-primary/10" />
                {t("restaurants.verifiedStore")}
              </DialogTitle>
              <DialogDescription className="text-sm leading-relaxed pt-2">
                {t("restaurants.verifiedStoreDesc")}
              </DialogDescription>
            </DialogHeader>
          </DialogContent>
        </Dialog>

        {/* Claim Restaurant Dialog */}
        <ClaimRestaurantDialog
          open={!!claimDialog}
          onOpenChange={(open) => !open && setClaimDialog(null)}
          restaurant={claimDialog}
        />
      </div>
    </div>
  );

  // Only wrap with PullToRefresh in list mode
  if (viewMode === "list") {
    return <PullToRefresh onRefresh={handleRefresh}>{pageContent}</PullToRefresh>;
  }

  return pageContent;
};

export default Restaurants;